// Helper to format today's date in YYYY-MM-DD
const getTodayStr = () => {
  const now = new Date();
  const year = now.getFullYear();
  const month = String(now.getMonth() + 1).padStart(2, '0');
  const day = String(now.getDate()).padStart(2, '0');
  return `${year}-${month}-${day}`;
};

// Date Reset Logic for Dailies and Weeklies
const resetTasksIfNeeded = (tasks) => {
  const now = new Date();
  const todayStr = getTodayStr();

  // Find last Monday date
  const dayOfWeek = now.getDay(); // 0 is Sunday, 1 is Monday, ...
  const diffToMonday = dayOfWeek === 0 ? 6 : dayOfWeek - 1;
  const lastMonday = new Date(now);
  lastMonday.setDate(now.getDate() - diffToMonday);
  lastMonday.setHours(0, 0, 0, 0);

  let updated = false;
  const updatedTasks = tasks.map(task => {
    if (task.is_done && task.last_done_date) {
      const parts = task.last_done_date.split('-');
      const lastDoneDate = new Date(parts[0], parts[1] - 1, parts[2]);
      lastDoneDate.setHours(0, 0, 0, 0);

      if (task.column === 'Dailies' && task.last_done_date !== todayStr) {
        updated = true;
        return {
          ...task,
          is_done: false,
          amount_now: task.task_type === 'progress' ? 0 : task.amount_now
        };
      } else if (task.column === 'Weeklies' && lastDoneDate < lastMonday) {
        updated = true;
        return {
          ...task,
          is_done: false,
          amount_now: task.task_type === 'progress' ? 0 : task.amount_now
        };
      }
    }
    return task;
  });

  return { tasks: updatedTasks, updated };
};

// CSV Parser
const parseCSV = (csvText) => {
  const lines = [];
  let currentLine = [];
  let currentCell = '';
  let inQuotes = false;

  for (let i = 0; i < csvText.length; i++) {
    const char = csvText[i];
    const nextChar = csvText[i + 1];

    if (inQuotes) {
      if (char === '"') {
        if (nextChar === '"') {
          currentCell += '"';
          i++;
        } else {
          inQuotes = false;
        }
      } else {
        currentCell += char;
      }
    } else {
      if (char === '"') {
        inQuotes = true;
      } else if (char === ',') {
        currentLine.push(currentCell);
        currentCell = '';
      } else if (char === '\r' || char === '\n') {
        currentLine.push(currentCell);
        currentCell = '';
        if (currentLine.length > 0 && (currentLine.length > 1 || currentLine[0] !== '')) {
          lines.push(currentLine);
        }
        currentLine = [];
        if (char === '\r' && nextChar === '\n') {
          i++;
        }
      } else {
        currentCell += char;
      }
    }
  }
  if (currentCell !== '' || currentLine.length > 0) {
    currentLine.push(currentCell);
    lines.push(currentLine);
  }

  if (lines.length < 2) return [];

  const headers = lines[0].map(h => h.trim());
  const rows = [];
  const validColumns = ["Weeklies", "Dailies", "Other / long term", "Materials"];

  for (let i = 1; i < lines.length; i++) {
    const line = lines[i];
    if (line.length < headers.length) continue;
    const row = {};
    headers.forEach((header, index) => {
      row[header] = line[index] || "";
    });

    if (!validColumns.includes(row.column)) continue;

    rows.push({
      id: row.id || (crypto.randomUUID ? crypto.randomUUID() : Math.random().toString(36).substring(2, 15)),
      column: row.column,
      category: row.category || "",
      task_name: row.task_name || "",
      is_subtask: row.is_subtask ? row.is_subtask.toUpperCase() === "TRUE" : false,
      parent_task: row.parent_task || "",
      is_alert: row.is_alert ? row.is_alert.toUpperCase() === "TRUE" : false,
      is_done: row.is_done ? row.is_done.toUpperCase() === "TRUE" : false,
      last_done_date: row.last_done_date || "",
      task_type: row.task_type || "checklist",
      amount_now: parseFloat(row.amount_now) || 0,
      amount_total: parseInt(row.amount_total) || 1,
      order: parseInt(row.order) || 0
    });
  }

  return rows;
};

// CSV Serializer
const exportTasksToCSV = (flatTasks) => {
  const headers = ["id", "column", "category", "task_name", "is_subtask", "parent_task", "is_alert", "is_done", "last_done_date", "task_type", "amount_now", "amount_total", "order"];
  const csvRows = [headers.join(",")];

  flatTasks.forEach(task => {
    const line = headers.map(header => {
      let val = task[header];
      if (val === undefined || val === null) {
        val = "";
      } else if (typeof val === 'boolean') {
        val = val ? "TRUE" : "FALSE";
      } else {
        val = String(val);
      }
      
      if (val.includes(",") || val.includes('"') || val.includes("\n") || val.includes("\r")) {
        return `"${val.replace(/"/g, '""')}"`;
      }
      return val;
    });
    csvRows.push(line.join(","));
  });

  return csvRows.join("\n");
};

// Build hierarchical structure from flat tasks
const buildDashboard = (flatTasks) => {
  const dashboard = {
    "Weeklies": [],
    "Dailies": [],
    "Other / long term": [],
    "Materials": []
  };

  const sortedTasks = [...flatTasks].sort((a, b) => {
    if (a.column !== b.column) {
      return a.column.localeCompare(b.column);
    }
    if (a.category !== b.category) {
      return (a.category || "").localeCompare(b.category || "");
    }
    return (a.order || 0) - (b.order || 0);
  });

  const currentSections = {
    "Weeklies": null,
    "Dailies": null,
    "Other / long term": null,
    "Materials": null
  };
  
  const parentRegistry = {};

  // First pass: Register non-subtasks
  sortedTasks.forEach((task, idx) => {
    const col = task.column;
    if (!dashboard[col]) return;

    const isSubtask = task.is_subtask;
    const category = task.category || "";

    if (!isSubtask) {
      if (category && currentSections[col] !== category) {
        currentSections[col] = category;
        dashboard[col].push({
          id: `sec_${col}_${category.replace(/\s+/g, '_')}_${idx}`,
          name: category,
          isSectionTitle: true,
          order: task.order || 0
        });
      }

      const newTask = {
        id: task.id,
        name: task.task_name,
        isHeader: (task.task_name === category) || (col === "Weeklies" && category !== ""),
        isAlert: task.is_alert,
        is_done: task.is_done,
        task_type: task.task_type || "checklist",
        amount_now: task.amount_now || 0,
        amount_total: task.amount_total || 1,
        order: task.order || 0,
        subtasks: []
      };

      parentRegistry[`${col}_${task.task_name}`] = newTask;
      dashboard[col].push(newTask);
    }
  });

  // Second pass: Process subtasks
  sortedTasks.forEach(task => {
    const col = task.column;
    if (!dashboard[col]) return;

    const isSubtask = task.is_subtask;
    if (isSubtask) {
      const parentName = task.parent_task;
      const registryKey = `${col}_${parentName}`;
      if (parentRegistry[registryKey]) {
        parentRegistry[registryKey].subtasks.push({
          id: task.id,
          name: task.task_name,
          isAlert: task.is_alert,
          is_done: task.is_done,
          task_type: task.task_type || "checklist",
          amount_now: task.amount_now || 0,
          amount_total: task.amount_total || 1,
          order: task.order || 0
        });
      }
    }
  });

  // Sort subtasks
  Object.keys(dashboard).forEach(col => {
    dashboard[col].forEach(task => {
      if (!task.isSectionTitle && task.subtasks) {
        task.subtasks.sort((a, b) => (a.order || 0) - (b.order || 0));
      }
    });
  });

  return dashboard;
};

function App() {
  const [isConfigured, setIsConfigured] = useState(!!localStorage.getItem("taskade_encrypted_tasks"));
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [password, setPassword] = useState("");
  const [tempPassword, setTempPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");
  const [authError, setAuthError] = useState("");
  const [isLoading, setIsLoading] = useState(false);

  const [flatTasks, setFlatTasks] = useState([]);
  const [columns, setColumns] = useState({});
  const [collapsedSections, setCollapsedSections] = useState({});
  const [showCompleted, setShowCompleted] = useState(false);
  const [addingToColumn, setAddingToColumn] = useState(null);
  const [addingToCategory, setAddingToCategory] = useState(null);
  const [newCategoryTaskName, setNewCategoryTaskName] = useState("");
  const [addingSubtaskTo, setAddingSubtaskTo] = useState(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [newTaskName, setNewTaskName] = useState("");
  const [newSubtaskName, setNewSubtaskName] = useState("");
  const [newTaskType, setNewTaskType] = useState("checklist");

  // Save changes helper
  const saveAndSetTasks = async (newFlatTasks, currentPassword) => {
    try {
      const encrypted = await encryptData(JSON.stringify(newFlatTasks), currentPassword);
      localStorage.setItem("taskade_encrypted_tasks", encrypted);
      setFlatTasks(newFlatTasks);
      const dashboard = buildDashboard(newFlatTasks);
      setColumns(dashboard);
    } catch (err) {
      console.error("Failed to encrypt and save tasks:", err);
    }
  };

  // Setup (Create Password & Import Default Tasks)
  const handleSetup = async (e) => {
    e.preventDefault();
    if (!tempPassword) {
      setAuthError("Password cannot be empty.");
      return;
    }
    if (tempPassword !== confirmPassword) {
      setAuthError("Passwords do not match.");
      return;
    }
    setIsLoading(true);
    setAuthError("");

    try {
      // Fetch default tasks CSV
      const res = await fetch('./tasks.csv');
      const csvText = await res.text();
      const parsedTasks = parseCSV(csvText);

      // Perform initial date check
      const { tasks: resetTasks } = resetTasksIfNeeded(parsedTasks);

      // Save encrypted
      await saveAndSetTasks(resetTasks, tempPassword);
      setPassword(tempPassword);
      setIsConfigured(true);
      setIsAuthenticated(true);
    } catch (err) {
      console.error(err);
      setAuthError("Failed to set up tasks database. Please try again.");
    } finally {
      setIsLoading(false);
    }
  };

  // Login
  const handleLogin = async (e) => {
    e.preventDefault();
    if (!tempPassword) {
      setAuthError("Please enter your password.");
      return;
    }
    setIsLoading(true);
    setAuthError("");

    try {
      const encryptedJson = localStorage.getItem("taskade_encrypted_tasks");
      const decryptedText = await decryptData(encryptedJson, tempPassword);
      const parsedTasks = JSON.parse(decryptedText);

      // Reset tasks based on date checks if needed
      const { tasks: resetTasks, updated } = resetTasksIfNeeded(parsedTasks);

      setPassword(tempPassword);
      setIsAuthenticated(true);

      if (updated) {
        await saveAndSetTasks(resetTasks, tempPassword);
      } else {
        setFlatTasks(resetTasks);
        setColumns(buildDashboard(resetTasks));
      }
    } catch (err) {
      setAuthError("Incorrect password or corrupted tasks database.");
    } finally {
      setIsLoading(false);
    }
  };

  // Sign out
  const handleSignOut = () => {
    setPassword("");
    setTempPassword("");
    setConfirmPassword("");
    setIsAuthenticated(false);
    setFlatTasks([]);
    setColumns({});
  };

  // Export CSV
  const handleExportCSV = () => {
    const csvContent = exportTasksToCSV(flatTasks);
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.setAttribute("href", url);
    link.setAttribute("download", `taskade_tasks_${getTodayStr()}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // Import CSV
  const handleImportCSV = (e) => {
    const file = e.target.files[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = async (event) => {
      try {
        const parsed = parseCSV(event.target.result);
        if (parsed.length === 0) {
          alert("Invalid CSV format or empty file.");
          return;
        }
        await saveAndSetTasks(parsed, password);
        alert("Tasks successfully imported!");
      } catch (err) {
        alert("Error parsing CSV file.");
      }
    };
    reader.readAsText(file);
    e.target.value = null; // Reset input
  };

  const toggleSection = (columnTitle, sectionId) => {
    setCollapsedSections(prev => ({
        ...prev,
        [`${columnTitle}-${sectionId}`]: !prev[`${columnTitle}-${sectionId}`]
    }));
  };

  const renameTask = (taskId, newName) => {
    let oldName = "";
    const updated = flatTasks.map(task => {
      if (task.id === taskId) {
        oldName = task.task_name;
        return { ...task, task_name: newName };
      }
      return task;
    });

    const finalTasks = updated.map(task => {
      if (oldName && task.is_subtask && task.parent_task === oldName) {
        return { ...task, parent_task: newName };
      }
      return task;
    });

    saveAndSetTasks(finalTasks, password);
  };

  const handleTaskNameChange = (columnTitle, taskId, newName) => {
    const updatedColumns = { ...columns };
    const findAndUpdate = (list) => {
      list.forEach(task => {
        if (task.id === taskId) {
          task.name = newName;
        } else if (task.subtasks) {
          findAndUpdate(task.subtasks);
        }
      });
    };
    findAndUpdate(updatedColumns[columnTitle]);
    setColumns(updatedColumns);
  };

  const handleUpdateProgress = (taskId, amountNow, amountTotal) => {
    const todayStr = getTodayStr();
    const finalTasks = flatTasks.map(task => {
      if (task.id === taskId) {
        const isDone = amountNow >= amountTotal;
        return {
          ...task,
          amount_now: amountNow,
          amount_total: amountTotal,
          is_done: isDone,
          last_done_date: isDone ? todayStr : task.last_done_date
        };
      }
      return task;
    });

    saveAndSetTasks(finalTasks, password);
  };

  const handleLocalProgressChange = (columnTitle, taskId, field, value) => {
    const updatedColumns = { ...columns };
    const findAndUpdate = (list) => {
      list.forEach(task => {
        if (task.id === taskId) {
          task[field] = value;
        } else if (task.subtasks) {
          findAndUpdate(task.subtasks);
        }
      });
    };
    findAndUpdate(updatedColumns[columnTitle]);
    setColumns(updatedColumns);
  };

  const toggleTask = (taskId, currentState) => {
    const newState = !currentState;
    const todayStr = getTodayStr();

    const finalTasks = flatTasks.map(task => {
      if (task.id === taskId) {
        const isProgress = task.task_type === 'progress';
        return {
          ...task,
          is_done: newState,
          last_done_date: newState ? todayStr : "",
          amount_now: isProgress ? (newState ? task.amount_total : 0) : task.amount_now
        };
      }
      return task;
    });

    saveAndSetTasks(finalTasks, password);
  };

  const deleteTask = (taskId) => {
    const finalTasks = flatTasks.filter(task => task.id !== taskId);
    saveAndSetTasks(finalTasks, password);
  };

  const handleAddTask = (columnTitle) => {
    if (!newTaskName.trim() || isSubmitting) return;
    setIsSubmitting(true);

    const filtered = flatTasks.filter(t => t.column === columnTitle && !t.category);
    const maxOrder = filtered.reduce((max, t) => Math.max(max, t.order || 0), -1);

    const newTask = {
      id: crypto.randomUUID ? crypto.randomUUID() : Math.random().toString(36).substring(2, 15),
      column: columnTitle,
      category: "",
      task_name: newTaskName,
      is_subtask: false,
      parent_task: "",
      is_alert: false,
      is_done: false,
      last_done_date: "",
      task_type: newTaskType,
      amount_now: 0,
      amount_total: newTaskType === 'progress' ? 100 : 1,
      order: maxOrder + 1
    };

    const finalTasks = [...flatTasks, newTask];
    saveAndSetTasks(finalTasks, password).then(() => {
      setNewTaskName("");
      setAddingToColumn(null);
      setNewTaskType("checklist");
      setIsSubmitting(false);
    });
  };

  const handleAddTaskInCategory = (columnTitle, category) => {
    if (!newCategoryTaskName.trim() || isSubmitting) return;
    setIsSubmitting(true);

    const filtered = flatTasks.filter(t => t.column === columnTitle && t.category === category);
    const maxOrder = filtered.reduce((max, t) => Math.max(max, t.order || 0), -1);

    const newTask = {
      id: crypto.randomUUID ? crypto.randomUUID() : Math.random().toString(36).substring(2, 15),
      column: columnTitle,
      category: category,
      task_name: newCategoryTaskName,
      is_subtask: false,
      parent_task: "",
      is_alert: false,
      is_done: false,
      last_done_date: "",
      task_type: newTaskType,
      amount_now: 0,
      amount_total: newTaskType === 'progress' ? 100 : 1,
      order: maxOrder + 1
    };

    const finalTasks = [...flatTasks, newTask];
    saveAndSetTasks(finalTasks, password).then(() => {
      setNewCategoryTaskName("");
      setAddingToCategory(null);
      setNewTaskType("checklist");
      setIsSubmitting(false);
    });
  };

  const handleAddSubtask = (columnTitle, parentName) => {
    if (!newSubtaskName.trim() || isSubmitting) return;
    setIsSubmitting(true);

    const filtered = flatTasks.filter(t => t.column === columnTitle && t.is_subtask && t.parent_task === parentName);
    const maxOrder = filtered.reduce((max, t) => Math.max(max, t.order || 0), -1);

    const newTask = {
      id: crypto.randomUUID ? crypto.randomUUID() : Math.random().toString(36).substring(2, 15),
      column: columnTitle,
      category: "",
      task_name: newSubtaskName,
      is_subtask: true,
      parent_task: parentName,
      is_alert: false,
      is_done: false,
      last_done_date: "",
      task_type: newTaskType,
      amount_now: 0,
      amount_total: newTaskType === 'progress' ? 100 : 1,
      order: maxOrder + 1
    };

    const finalTasks = [...flatTasks, newTask];
    saveAndSetTasks(finalTasks, password).then(() => {
      setNewSubtaskName("");
      setAddingSubtaskTo(null);
      setNewTaskType("checklist");
      setIsSubmitting(false);
    });
  };

  const onDragEnd = (result) => {
    const { source, destination } = result;
    if (!destination) return;
    if (source.droppableId === destination.droppableId && source.index === destination.index) return;

    const columnTitle = source.droppableId;
    const newItems = Array.from(columns[columnTitle]);
    const [reorderedItem] = newItems.splice(source.index, 1);
    newItems.splice(destination.index, 0, reorderedItem);

    const updatedColumns = {
      ...columns,
      [columnTitle]: newItems,
    };
    setColumns(updatedColumns);

    let currentCategory = "";
    const taskUpdates = {};
    newItems.forEach((item, index) => {
      if (item.isSectionTitle) {
        currentCategory = item.name;
      } else {
        taskUpdates[item.id] = {
          order: index,
          category: currentCategory
        };
      }
    });

    const finalTasks = flatTasks.map(task => {
      if (taskUpdates[task.id]) {
        return {
          ...task,
          order: taskUpdates[task.id].order,
          category: taskUpdates[task.id].category
        };
      }
      return task;
    });

    saveAndSetTasks(finalTasks, password);
  };

  // Auth Screens Rendering
  if (!isConfigured || !isAuthenticated) {
    return (
      <div className="auth-container">
        <div className="auth-card">
          <h2>
            <KeyIcon />
            {isConfigured ? "Unlock Workspace" : "Setup Secure Workspace"}
          </h2>
          <p className="auth-subtitle">
            {isConfigured 
              ? "Enter your password to decrypt and open your productivity dashboard." 
              : "Choose a master password to encrypt and secure your task data locally in your browser."}
          </p>
          <form onSubmit={isConfigured ? handleLogin : handleSetup}>
            <div className="auth-field">
              <label>Password</label>
              <input 
                type="password"
                placeholder={isConfigured ? "Enter password..." : "Choose password..."}
                value={tempPassword}
                onChange={(e) => setTempPassword(e.target.value)}
                autoFocus
              />
            </div>
            {!isConfigured && (
              <div className="auth-field">
                <label>Confirm Password</label>
                <input 
                  type="password"
                  placeholder="Repeat password..."
                  value={confirmPassword}
                  onChange={(e) => setConfirmPassword(e.target.value)}
                />
              </div>
            )}
            {authError && <div className="auth-error">{authError}</div>}
            <button type="submit" disabled={isLoading} className="auth-submit-btn">
              {isLoading ? "Processing..." : isConfigured ? "Unlock" : "Initialize Database"}
            </button>
          </form>
          {!isConfigured && (
            <div className="setup-tip">
              <strong>Tip:</strong> Your password is used for AES-256 encryption. We never send it to any server. Keep it safe!
            </div>
          )}
        </div>
      </div>
    );
  }

  // Dashboard Rendering
  return (
    <div className="app-wrapper">
      <div className="cosmetic-header">
        <h1>Taskade Clone</h1>
      </div>
      <div className="top-bar">
        <div className="top-bar-controls">
          <label className="import-btn-label" title="Import CSV Backup">
            <ImportIcon /> Import CSV
            <input 
              type="file" 
              accept=".csv" 
              onChange={handleImportCSV} 
              style={{ display: 'none' }}
            />
          </label>
          <button 
            className="action-bar-btn" 
            onClick={handleExportCSV}
            title="Download CSV Backup"
          >
            <ExportIcon /> Export CSV
          </button>
          <button 
            className="toggle-completed-btn" 
            onClick={() => setShowCompleted(!showCompleted)}
            title={showCompleted ? "Showing completed" : "Hiding completed"}
          >
            {showCompleted ? <EyeIcon /> : <EyeOffIcon />}
          </button>
          <button 
            className="sign-out-btn" 
            onClick={handleSignOut}
            title="Lock Workspace"
          >
            <SignOutIcon /> Lock
          </button>
        </div>
      </div>
      
      <DragDropContext onDragEnd={onDragEnd}>
        <div className="dashboard-container">
          {Object.keys(columns).map((columnTitle) => (
            <div key={columnTitle} className="task-card">
              <h2>{columnTitle}</h2>

              <Droppable droppableId={columnTitle}>
                {(provided) => (
                  <div 
                    className="task-list"
                    {...provided.droppableProps}
                    ref={provided.innerRef}
                  >
                    {(() => {
                      let currentSection = null;
                      return columns[columnTitle].map((task, index) => {
                        if (task.isSectionTitle) {
                          currentSection = task.id;
                          const sectionId = `${columnTitle}-${task.id}`;
                          return (
                            <Draggable key={task.id} draggableId={task.id} index={index}>
                              {(provided) => (
                                <div
                                  ref={provided.innerRef}
                                  {...provided.draggableProps}
                                  {...provided.dragHandleProps}
                                >
                                  <div className="section-title-wrapper" style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginTop: '15px', marginBottom: '10px' }}>
                                    <h3 
                                        className="section-title" 
                                        onClick={() => toggleSection(columnTitle, task.id)}
                                        style={{ cursor: 'pointer', margin: 0 }}
                                    >
                                        {collapsedSections[sectionId] ? '▶' : '▼'} {task.name}
                                    </h3>
                                    <button 
                                        className="add-task-to-cat-btn"
                                        onClick={(e) => {
                                            e.stopPropagation();
                                            setAddingToCategory(sectionId);
                                        }}
                                        style={{ background: 'transparent', border: '1px solid #555a61', color: '#fff', cursor: 'pointer', fontSize: '1.2rem', padding: '0 8px', borderRadius: '4px', zIndex: 100, position: 'relative' }}
                                    >+</button>
                                  </div>
                                  {addingToCategory === sectionId && (
                                      <div className="add-task-form" style={{ marginTop: '0', marginBottom: '10px' }}>
                                        <div className="add-task-form-header">
                                          <span style={{ fontSize: '0.75rem', color: '#555a61' }}>Add to {task.name}</span>
                                          <div className="type-selectors">
                                            <button 
                                              className={`type-toggle-btn ${newTaskType === 'checklist' ? 'active' : ''}`}
                                              onClick={() => setNewTaskType('checklist')}
                                            >Check</button>
                                            <button 
                                              className={`type-toggle-btn ${newTaskType === 'progress' ? 'active' : ''}`}
                                              onClick={() => setNewTaskType('progress')}
                                            >Prog</button>
                                          </div>
                                        </div>
                                        <input 
                                          type="text" 
                                          autoFocus
                                          placeholder={newTaskType === 'progress' ? "Material/Progress name..." : "New task..."}
                                          value={newCategoryTaskName}
                                          onChange={(e) => setNewCategoryTaskName(e.target.value)}
                                          onKeyDown={(e) => {
                                            if (e.key === 'Enter') {
                                                handleAddTaskInCategory(columnTitle, task.name);
                                            }
                                            if (e.key === 'Escape') {
                                              setAddingToCategory(null);
                                              setNewCategoryTaskName("");
                                              setNewTaskType("checklist");
                                            }
                                          }}
                                          onBlur={() => {
                                            if (!newCategoryTaskName.trim()) {
                                              setAddingToCategory(null);
                                              setNewTaskType("checklist");
                                            }
                                          }}
                                        />
                                      </div>
                                  )}
                                </div>
                              )}
                            </Draggable>
                          );
                        }

                        if (currentSection && collapsedSections[`${columnTitle}-${currentSection}`]) {
                          return null;
                        }
                        const isTaskCompleted = task.is_done;
                        if (!showCompleted && isTaskCompleted) return null;

                        const progress = task.task_type === 'progress' 
                          ? Math.min(100, Math.max(0, (task.amount_now / task.amount_total) * 100))
                          : 0;

                        return (
                          <Draggable key={task.id} draggableId={task.id} index={index}>
                            {(provided) => (
                              <div 
                                className={`task-group ${isTaskCompleted ? 'completed' : ''}`}
                                ref={provided.innerRef}
                                {...provided.draggableProps}
                                {...provided.dragHandleProps}
                              >
                                <div className="task-main-row">
                                  <label className={`task-item ${task.isAlert ? 'alert-text' : ''} ${isTaskCompleted ? 'completed' : ''}`}>
                                    <input 
                                      type="checkbox" 
                                      checked={isTaskCompleted}
                                      onChange={() => toggleTask(task.id, isTaskCompleted)}
                                    />
                                    <span className="checkmark"></span>
                                    <input 
                                        type="text" 
                                        id={`task-name-${task.id}`}
                                        name="task-name"
                                        className="task-name-input"
                                        value={task.name}
                                        onChange={(e) => handleTaskNameChange(columnTitle, task.id, e.target.value)}
                                        onBlur={() => renameTask(task.id, task.name)}
                                        onKeyDown={(e) => { if(e.key === 'Enter') e.target.blur(); }}
                                    />
                                  </label>
                                  {task.task_type === 'progress' && (
                                    <div className="task-progress-controls">
                                      <input 
                                        type="number"
                                        className="progress-input"
                                        value={task.amount_now}
                                        onChange={(e) => handleLocalProgressChange(columnTitle, task.id, 'amount_now', e.target.value)}
                                        onBlur={() => handleUpdateProgress(task.id, parseFloat(task.amount_now) || 0, parseInt(task.amount_total) || 1)}
                                        onKeyDown={(e) => { if(e.key === 'Enter') e.target.blur(); }}
                                      />
                                      <span>/</span>
                                      <input 
                                        type="number"
                                        className="progress-total"
                                        value={task.amount_total}
                                        onChange={(e) => handleLocalProgressChange(columnTitle, task.id, 'amount_total', e.target.value)}
                                        onBlur={() => handleUpdateProgress(task.id, parseInt(task.amount_now) || 0, parseInt(task.amount_total) || 1)}
                                        onKeyDown={(e) => { if(e.key === 'Enter') e.target.blur(); }}
                                      />
                                    </div>
                                  )}
                                  <div className="task-actions">
                                    <button 
                                      className="add-subtask-icon icon-btn" 
                                      onClick={() => setAddingSubtaskTo(task.id)}
                                      title="Add subtask"
                                    >
                                      +
                                    </button>
                                    <button 
                                      className="delete-item-btn icon-btn" 
                                      onClick={() => deleteTask(task.id)}
                                      title="Delete task"
                                    >
                                      <TrashIcon />
                                    </button>
                                  </div>
                                </div>
                                {task.task_type === 'progress' && (
                                  <div className="progress-container">
                                    <div 
                                      className={`progress-bar ${progress >= 100 ? 'completed' : ''}`}
                                      style={{ width: `${progress}%` }}
                                    ></div>
                                  </div>
                                )}
                                {task.subtasks && task.subtasks.map((sub) => {
                                  const isSubCompleted = sub.is_done;
                                  if (!showCompleted && isSubCompleted) return null;
                                  const subProgress = sub.task_type === 'progress' 
                                    ? Math.min(100, Math.max(0, (sub.amount_now / sub.amount_total) * 100))
                                    : 0;

                                  return (
                                    <div key={sub.id} className={`subtask-group ${isSubCompleted ? 'completed' : ''}`}>
                                      <div className="task-main-row subtask-row">
                                        <label className={`task-item subtask ${isSubCompleted ? 'completed' : ''}`}>
                                          <input 
                                            type="checkbox" 
                                            checked={isSubCompleted}
                                            onChange={() => toggleTask(sub.id, isSubCompleted)}
                                          />
                                          <span className="checkmark"></span>
                                          <input 
                                              type="text" 
                                              id={`subtask-name-${sub.id}`}
                                              name="subtask-name"
                                              className="task-name-input"
                                              value={sub.name}
                                              onChange={(e) => handleTaskNameChange(columnTitle, sub.id, e.target.value)}
                                              onBlur={() => renameTask(sub.id, sub.name)}
                                              onKeyDown={(e) => { if(e.key === 'Enter') e.target.blur(); }}
                                          />
                                        </label>
                                        {sub.task_type === 'progress' && (
                                          <div className="task-progress-controls">
                                            <input 
                                              type="number"
                                              className="progress-input"
                                              value={sub.amount_now}
                                              onChange={(e) => handleLocalProgressChange(columnTitle, sub.id, 'amount_now', e.target.value)}
                                              onBlur={() => handleUpdateProgress(sub.id, parseInt(sub.amount_now) || 0, parseInt(sub.amount_total) || 1)}
                                              onKeyDown={(e) => { if(e.key === 'Enter') e.target.blur(); }}
                                            />
                                            <span>/</span>
                                            <input 
                                              type="number"
                                              className="progress-total"
                                              value={sub.amount_total}
                                              onChange={(e) => handleLocalProgressChange(columnTitle, sub.id, 'amount_total', e.target.value)}
                                              onBlur={() => handleUpdateProgress(sub.id, parseInt(sub.amount_now) || 0, parseInt(sub.amount_total) || 1)}
                                              onKeyDown={(e) => { if(e.key === 'Enter') e.target.blur(); }}
                                            />
                                          </div>
                                        )}
                                        <button 
                                          className="delete-item-btn icon-btn" 
                                          onClick={() => deleteTask(sub.id)}
                                          title="Delete subtask"
                                        >
                                          <TrashIcon />
                                        </button>
                                      </div>
                                      {sub.task_type === 'progress' && (
                                        <div className="progress-container" style={{ marginLeft: '63px' }}>
                                          <div 
                                            className={`progress-bar ${subProgress >= 100 ? 'completed' : ''}`}
                                            style={{ width: `${subProgress}%` }}
                                          ></div>
                                        </div>
                                      )}
                                    </div>
                                  );
                                })}
                                {addingSubtaskTo === task.id && (
                                <div className="add-task-form subtask-form">
                                  <div className="add-task-form-header">
                                    <span style={{ fontSize: '0.75rem', color: '#555a61' }}>Add subtask</span>
                                    <div className="type-selectors">
                                      <button 
                                        className={`type-toggle-btn ${newTaskType === 'checklist' ? 'active' : ''}`}
                                        onClick={() => setNewTaskType('checklist')}
                                      >Check</button>
                                      <button 
                                        className={`type-toggle-btn ${newTaskType === 'progress' ? 'active' : ''}`}
                                        onClick={() => setNewTaskType('progress')}
                                      >Prog</button>
                                    </div>
                                  </div>
                                  <input 
                                    type="text" 
                                    id={`new-subtask-in-task-${task.id}`}
                                    name="new-subtask-in-task"
                                    autoFocus
                                    placeholder="Subtask name..."
                                    value={newSubtaskName}
                                    onChange={(e) => setNewSubtaskName(e.target.value)}
                                    onKeyDown={(e) => {
                                      if (e.key === 'Enter') handleAddSubtask(columnTitle, task.name);
                                      if (e.key === 'Escape') {
                                        setAddingSubtaskTo(null);
                                        setNewSubtaskName("");
                                        setNewTaskType("checklist");
                                      }
                                    }}
                                    onBlur={() => {
                                      if (!newSubtaskName.trim()) {
                                        setAddingSubtaskTo(null);
                                        setNewTaskType("checklist");
                                      }
                                    }}
                                  />
                                </div>
                                )}
                              </div>
                            )}
                          </Draggable>
                        );
                      });
                    })()}
                    {provided.placeholder}
                  </div>
                )}
              </Droppable>

              {addingToColumn === columnTitle ? (
                <div className="add-task-form">
                  <div className="add-task-form-header">
                    <span style={{ fontSize: '0.75rem', color: '#555a61' }}>Add to {columnTitle}</span>
                    <div className="type-selectors">
                      <button 
                        className={`type-toggle-btn ${newTaskType === 'checklist' ? 'active' : ''}`}
                        onClick={() => setNewTaskType('checklist')}
                      >Check</button>
                      <button 
                        className={`type-toggle-btn ${newTaskType === 'progress' ? 'active' : ''}`}
                        onClick={() => setNewTaskType('progress')}
                      >Prog</button>
                    </div>
                  </div>
                  <input 
                    type="text" 
                    id={`new-task-in-col-${columnTitle}`}
                    name="new-task-in-col"
                    autoFocus
                    placeholder="Task name..."
                    value={newTaskName}
                    onChange={(e) => setNewTaskName(e.target.value)}
                    onKeyDown={(e) => {
                      if (e.key === 'Enter') handleAddTask(columnTitle);
                      if (e.key === 'Escape') {
                        setAddingToColumn(null);
                        setNewTaskName("");
                        setNewTaskType("checklist");
                      }
                    }}
                    onBlur={() => {
                      if (!newTaskName.trim()) {
                        setAddingToColumn(null);
                        setNewTaskType("checklist");
                      }
                    }}
                  />
                </div>
              ) : (
                <div className="add-task-btn" onClick={() => setAddingToColumn(columnTitle)}>
                  + Add Task
                </div>
              )}
            </div>
          ))}
        </div>
      </DragDropContext>
    </div>
  );
}

export default App;
